using System;using System.Collections.Generic;using System.Linq;
public class Program{static bool Pal(string s){for(int i=0,j=s.Length-1;i<j;i++,j--)if(s[i]!=s[j])return false;return true;}static string Rev(string s){char[] a=s.ToCharArray();Array.Reverse(a);return new string(a);}static List<int[]> Solve(string[] w){var pos=new Dictionary<string,int>();for(int i=0;i<w.Length;i++)pos[w[i]]=i;var ans=new List<int[]>();for(int i=0;i<w.Length;i++){for(int c=0;c<=w[i].Length;c++){string pre=w[i].Substring(0,c),suf=w[i].Substring(c);int j;if(Pal(pre)&&pos.TryGetValue(Rev(suf),out j)&&j!=i)ans.Add(new[]{j,i});if(c<w[i].Length&&Pal(suf)&&pos.TryGetValue(Rev(pre),out j)&&j!=i)ans.Add(new[]{i,j});}}ans.Sort((a,b)=>a[0]==b[0]?a[1]-b[1]:a[0]-b[0]);return ans;}static string Fmt(List<int[]> p){return "["+string.Join(",",p.ConvertAll(q=>"["+q[0]+","+q[1]+"]"))+ "]";}public static void Main(){string[] d=Console.In.ReadToEnd().Split((char[])null,StringSplitOptions.RemoveEmptyEntries);if(d.Length==0)return;int idx=0,t=int.Parse(d[idx++]);var outv=new List<string>();for(int tc=0;tc<t;tc++){int n=int.Parse(d[idx++]);string[] w=new string[n];for(int i=0;i<n;i++){w[i]=d[idx++];if(w[i]=="_")w[i]="";}outv.Add(Fmt(Solve(w)));}Console.Write(string.Join("\n\n",outv));}}
